def validate_redirect_uri(redirect_uri, tenant_config):
    """
    Securely validate redirect URI against allowed list.
    Uses exact match validation instead of substring matching.
    """
    if not redirect_uri:
        return False
    
    # Parse the redirect URI
    try:
        parsed = urlparse(redirect_uri)
    except Exception:
        return False
    
    # Ensure HTTPS only
    if parsed.scheme != 'https':
        return False
    
    # Exact match against allowed redirect URIs
    if redirect_uri in tenant_config.get('allowed_redirect_uris', []):
        return True
    
    return False


def validate_domain_ownership(redirect_uri, domain):
    """
    Validate that redirect URI belongs to the configured domain.
    Uses proper hostname parsing instead of substring matching.
    """
    try:
        parsed = urlparse(redirect_uri)
        hostname = parsed.hostname
        
        if not hostname:
            return False
        
        # Check if hostname exactly matches domain or is a subdomain
        if hostname == domain:
            return True
        
        # Check if it's a valid subdomain (ends with .domain)
        if hostname.endswith('.' + domain):
            return True
        
        return False
    except Exception:
        return False


def generate_state_token():
    """Generate cryptographically secure state token"""
    return secrets.token_urlsafe(32)


def verify_state_token(provided_state):
    """Verify state token from session"""
    stored_state = session.get('oauth_state')
    if not stored_state or not provided_state:
        return False
    return hmac.compare_digest(stored_state, provided_state)


