def exchange_code_for_token(code, redirect_uri, tenant_config):
    """
    Exchange authorization code for access token.
    In production, use requests library with proper SSL verification.
    """
    import requests
    
    token_params = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': redirect_uri,
        'client_id': tenant_config['client_id'],
        'client_secret': tenant_config['client_secret']
    }
    
    try:
        response = requests.post(
            tenant_config['token_endpoint'],
            data=token_params,
            headers={'Accept': 'application/json'},
            timeout=10,
            verify=True  # Always verify SSL certificates
        )
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        # Log error securely without exposing sensitive data
        app.logger.error(f'Token exchange failed for tenant')
        abort(500, 'Token exchange failed')


